{
  "type": "QUIZ",
  "lessonText": "Test your understanding of simple melodies with this quiz.",
  "data": {
    "questions": [
      {
        "question": "What is a simple melody?",
        "options": [
          "A complex arrangement of chords",
          "A sequence of notes that is easy to play",
          "A rhythm without melody",
          "A type of harmony"
        ],
        "correctAnswer": 1,
        "explanation": "A simple melody is characterized by a sequence of notes that is easy to play."
      },
      {
        "question": "Which of the following is NOT a characteristic of simple melodies?",
        "options": [
          "Repetitive patterns",
          "Use of complex rhythms",
          "Short phrases",
          "Limited range"
        ],
        "correctAnswer": 1,
        "explanation": "Complex rhythms are not typically a characteristic of simple melodies."
      },
      {
        "question": "How can you practice playing simple melodies?",
        "options": [
          "By playing scales only",
          "By improvising with chords",
          "By using sheet music with simple tunes",
          "By focusing on advanced techniques"
        ],
        "correctAnswer": 2,
        "explanation": "Using sheet music with simple tunes is an effective way to practice playing simple melodies."
      },
      {
        "question": "Which instrument is commonly used to play simple melodies?",
        "options": [
          "Drums",
          "Guitar",
          "Piano",
          "Saxophone"
        ],
        "correctAnswer": 2,
        "explanation": "The piano is widely used to play simple melodies due to its versatility and accessibility."
      }
    ]
  }
}
